  1	import React, { FC, memo, useEffect, useState } from 'react';
  2	
  3	import ExternalLink from '@kubevirt-utils/components/ExternalLink/ExternalLink';
  4	import HelpTextIcon from '@kubevirt-utils/components/HelpTextIcon/HelpTextIcon';
  5	import { documentationURL } from '@kubevirt-utils/constants/documentation';
  6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  7	import {
  8	  pluralize,
  9	  SearchInput,
 10	  Split,
 11	  SplitItem,
 12	  ToggleGroup,
 13	  ToggleGroupItem,
 14	} from '@patternfly/react-core';
 15	import { ListIcon, ThIcon } from '@patternfly/react-icons';
 16	
 17	import { CATALOG_FILTERS } from '../utils/consts';
 18	import { hasNoDefaultUserAllFilters } from '../utils/helpers';
 19	import { TemplateFilters } from '../utils/types';
 20	
 21	export const TemplatesCatalogHeader: FC<{
 22	  filters: TemplateFilters;
 23	  itemCount: number;
 24	  onFilterChange: (type: CATALOG_FILTERS, value: boolean | string) => void;
 25	}> = memo(({ filters, itemCount, onFilterChange }) => {
 26	  const { t } = useKubevirtTranslation();
 27	  const [query, setQuery] = useState<string>(filters?.query || '');
 28	
 29	  useEffect(
 30	    () => {
 31	      // Update debounced value after delay
 32	      const handler = setTimeout(() => {
 33	        onFilterChange(CATALOG_FILTERS.QUERY, query);
 34	      }, 150);
 35	      // Cancel the timeout if value changes (also on delay change or unmount)
 36	      return () => {
 37	        clearTimeout(handler);
 38	      };
 39	    },
 40	    // eslint-disable-next-line react-hooks/exhaustive-deps
 41	    [query], // Only re-call effect if value or delay changes
 42	  );
 43	
 44	  return (
 45	    <div className="co-catalog-page__header">
 46	      <div className="co-catalog-page__heading text-capitalize">
 47	        {(filters?.onlyDefault || hasNoDefaultUserAllFilters(filters)) && (
 48	          <>
 49	            {t('Default templates')}{' '}
 50	            <HelpTextIcon
 51	              bodyContent={
 52	                <>
 53	                  {t('Red Hat recommended configuration for each OS.')}{' '}
 54	                  <ExternalLink
 55	                    href={documentationURL.CREATING_VMS_FROM_TEMPLATES}
 56	                    text={t('Learn more')}
 57	                  />
 58	                </>
 59	              }
 60	            />
 61	          </>
 62	        )}
 63	        {filters?.onlyUser && t('User templates')}
 64	        {filters?.allItems && t('All templates')}
 65	      </div>
 66	      <div className="co-catalog-page__filter">
 67	        <div>
 68	          <SearchInput
 69	            onChange={(_, val) => {
 70	              setQuery(val);
 71	            }}
 72	            onClear={() => {
 73	              setQuery('');
 74	              onFilterChange(CATALOG_FILTERS.QUERY, '');
 75	            }}
 76	            aria-label={t('Filter by keyword...')}
 77	            className="co-catalog-page__input"
 78	            data-test="search-catalog"
 79	            id="filter-text-input"
 80	            placeholder={t('Filter by keyword...')}
 81	            type="text"
 82	            value={filters?.query}
 83	          />
 84	        </div>
 85	
 86	        <Split hasGutter>
 87	          <SplitItem>
 88	            <div className="co-catalog-page__num-items">{pluralize(itemCount, 'item')}</div>
 89	          </SplitItem>
 90	          <SplitItem>
 91	            <ToggleGroup aria-label="list-or-grid-toggle" isCompact>
 92	              <ToggleGroupItem
 93	                aria-label="template list button"
 94	                buttonId="template-list-btn"
 95	                icon={<ListIcon />}
 96	                isSelected={filters?.isList}
 97	                onChange={() => onFilterChange(CATALOG_FILTERS.IS_LIST, true)}
 98	              />
 99	              <ToggleGroupItem
100	                aria-label="template grid button"
101	                buttonId="template-grid-btn"
102	                icon={<ThIcon />}
103	                isSelected={!filters?.isList}
104	                onChange={() => onFilterChange(CATALOG_FILTERS.IS_LIST, false)}
105	              />
106	            </ToggleGroup>
107	          </SplitItem>
108	        </Split>
109	      </div>
110	    </div>
111	  );
112	});
113	TemplatesCatalogHeader.displayName = 'TemplatesCatalogHeader';

